#include <stdio.h>
#include <stdlib.h>
typedef struct { long long s, e; } Interval;
int cmp(const void *a, const void *b) {
    Interval *x = (Interval *)a, *y = (Interval *)b;
    if (x->s != y->s) return (x->s < y->s) ? -1 : 1;
    return (x->e < y->e) ? -1 : (x->e > y->e);
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; long long K, F; scanf("%d %lld %lld", &N, &K, &F);
        Interval *arr = (Interval*)malloc(N * sizeof(Interval));
        for (int i = 0; i < N; ++i) scanf("%lld %lld", &arr[i].s, &arr[i].e);
        qsort(arr, N, sizeof(Interval), cmp);
        long long covered = 0;
        long long curL = -1, curR = -1;
        for (int i = 0; i < N; ++i) {
            if (curL == -1) { curL = arr[i].s; curR = arr[i].e; }
            else if (arr[i].s <= curR) { if (arr[i].e > curR) curR = arr[i].e; }
            else { covered += curR - curL; curL = arr[i].s; curR = arr[i].e; }
        }
        if (curL != -1) covered += curR - curL;
        long long freeTime = F - covered;
        printf(freeTime >= K ? "YES\n" : "NO\n");
        free(arr);
    }
    return 0;
}

