import java.io.*;
import java.util.*;
public class Main {
    static class FastScanner {
        private final BufferedInputStream in = new BufferedInputStream(System.in);
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner();
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long K = fs.nextLong();
            long F = fs.nextLong();
            long[][] seg = new long[N][2];
            for (int i = 0; i < N; ++i) {
                seg[i][0] = fs.nextLong();
                seg[i][1] = fs.nextLong();
            }
            Arrays.sort(seg, Comparator.comparingLong(a -> a[0]));
            long covered = 0;
            long curL = -1, curR = -1;
            for (long[] p : seg) {
                if (curL == -1) { curL = p[0]; curR = p[1]; }
                else if (p[0] <= curR) { if (p[1] > curR) curR = p[1]; }
                else { covered += curR - curL; curL = p[0]; curR = p[1]; }
            }
            if (curL != -1) covered += curR - curL;
            long free = F - covered;
            sb.append(free >= K ? "YES" : "NO").append('\n');
        }
        System.out.print(sb.toString());
    }
}

