#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it)); K = int(next(it)); F = int(next(it))
        intervals = []
        for __ in range(n):
            s = int(next(it)); e = int(next(it))
            intervals.append((s, e))
        intervals.sort()
        covered = 0
        curL = curR = None
        for s, e in intervals:
            if curL is None:
                curL, curR = s, e
            elif s <= curR:
                if e > curR:
                    curR = e
            else:
                covered += curR - curL
                curL, curR = s, e
        if curL is not None:
            covered += curR - curL
        free = F - covered
        out_lines.append("YES" if free >= K else "NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

