    const s = Number(data[idx++]);
    const e = Number(data[idx++]);
    intervals[i] = [s, e];
  }
  intervals.sort((a, b) => a[0] - b[0]);
  let covered = 0;
  let curL = null, curR = null;
  for (const [s, e] of intervals) {
    if (curL === null) { curL = s; curR = e; }
    else if (s <= curR) { if (e > curR) curR = e; }
    else { covered += curR - curL; curL = s; curR = e; }
  }
  if (curL !== null) covered += curR - curL;
  const free = F - covered;
  out.push(free >= K ? 'YES' : 'NO');
}
